import React, { useRef, useEffect } from "react";

/**
 * OTPInput — 6-digit OTP input with keyboard nav, paste support, and responsive sizing.
 * Sizing is handled by .otp-box CSS class (see global.css breakpoints).
 */
export default function OTPInput({ value, onChange, hasError = false, length = 6 }) {
  const inputRefs = useRef([]);
  const [focused, setFocused] = React.useState(null);

  useEffect(() => { inputRefs.current[0]?.focus(); }, []);

  function handleChange(index, e) {
    const char = e.target.value.replace(/\D/g, "").slice(-1);
    const next = [...value];
    next[index] = char;
    onChange(next);
    if (char && index < length - 1) inputRefs.current[index + 1]?.focus();
  }

  function handleKeyDown(index, e) {
    if (e.key === "Backspace") {
      if (value[index]) { const n = [...value]; n[index] = ""; onChange(n); }
      else if (index > 0) inputRefs.current[index - 1]?.focus();
    }
    if (e.key === "ArrowLeft"  && index > 0)           inputRefs.current[index - 1]?.focus();
    if (e.key === "ArrowRight" && index < length - 1)  inputRefs.current[index + 1]?.focus();
  }

  function handlePaste(e) {
    e.preventDefault();
    const pasted = e.clipboardData.getData("text").replace(/\D/g, "").slice(0, length);
    const next = Array(length).fill("");
    pasted.split("").forEach((ch, i) => { next[i] = ch; });
    onChange(next);
    inputRefs.current[Math.min(pasted.length, length - 1)]?.focus();
  }

  function borderColor() {
    if (hasError) return "1.5px solid var(--error)";
    return "1.5px solid var(--border)";
  }

  return (
    <div style={{ display: "flex", gap: "8px", marginTop: "8px" }} onPaste={handlePaste}>
      {Array.from({ length }, (_, i) => (
        <input
          key={i}
          ref={(el) => (inputRefs.current[i] = el)}
          /* otp-box class drives responsive sizing via CSS breakpoints */
          className="otp-box"
          type="text"
          inputMode="numeric"
          pattern="\d*"
          maxLength={1}
          value={value[i] || ""}
          onChange={(e) => handleChange(i, e)}
          onKeyDown={(e) => handleKeyDown(i, e)}
          onFocus={() => setFocused(i)}
          onBlur={() => setFocused(null)}
          aria-label={`OTP digit ${i + 1}`}
          style={{
            border: focused === i && !hasError ? "1.5px solid var(--brand)" : borderColor(),
            outline: "none",
            fontFamily: "var(--font-primary)",
            transition: "border .15s",
            color: "var(--text-primary)",
            background: "var(--input-bg)",
          }}
        />
      ))}
    </div>
  );
}
